mapper.select:
SELECT UserId, FullName, Email, PasswordHash, Phone, Address, RoleName, CreatedAt, Username
FROM Users
WHERE Username = #{username}

SELECT UserId, FullName, Email, PasswordHash, Phone, Address, RoleName, CreatedAt, Username
FROM Users
WHERE UserId = #{id}

SELECT * FROM Users
WHERE (Username = #{username} OR Email = #{username})
  AND PasswordHash = #{password}
